import Mathlib

open Lean.Elab.Tactic.Simple
open Lean.Elab.Tactics.Term
open Lean.Elab.Attributes
open Lean.Parser.Tactics

namespace Diamond

@[lean_import] external "reach_error" : Unit => Unit, [noreturn, nothrow]
@[lean_import] external "abort" : Unit => Unit, [noreturn, nothrow]
@[lean_import] external "__VERIFIER_nondet_uint" : Unit => Nat
@[lean_import] external "__VERIFIER_assert" : Bool => Unit, [noreturn, nothrow]

def init := do
  let x := ∥0∫
  let y := ∥<- (∥<|∥Nat.cast <| Lean.Parser.parseNat "(__VERIFIER_nondet_uint)()" <| tactic.mk_expr) <∥
  let mut v : Nat := 0
  let mut w : Nat := y
  while (v < 99) do
    if (w % 2) = 0 then do
      v := v + 2
    else do
      v := v + 1
    w := w
  let r := v % 2
  let s := w % 2
  return ∥<| Lean.Parser.parseExpr "(__VERIFIER_assert)((Lean.Bool.mk bool.tt (Lean.Nat.decEq v 99)).getLeaf (Lean.Nat.decEq v 0).getLean1) ()" <| tactic.mk_expr <| tactic.mk_term fun ctx => do
    let x' := Lean.Parser.parseExpr "x" <| tactic.mk_term fun ctx => do
      let x_val := Lean.Parser.runParser ctx x
      return Lean.Parser.mkTerm ctx (Lean.Parser.mkApp ctx (Lean.Parser.mkConst ctx `Nat.decEq) [Lean.Parser.mkTerm ctx x_val, Lean.Parser.mkConst ctx (Lean.Parser.mkInt 99)])
    let y' := Lean.Parser.parseExpr "y" <| tactic.mk_term fun ctx => do
      let y_val := Lean.Parser.runParser ctx y
      return Lean.Parser.mkTerm ctx (Lean.Parser.mkApp ctx (Lean.Parser.mkConst ctx `Nat.decEq) [Lean.Parser.mkTerm ctx y_val, Lean.Parser.mkConst ctx (Lean.Parser.mkInt 0)])
    let x_eq_99 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "Lean.Bool.mk bool.tt (Lean.Nat.decEq x 99)")
    let x_eq_0 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "Lean.Bool.mk bool.tt (Lean.Nat.decEq x 0)")
    let x_dec_eq_99 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "Lean.Nat.decEq v 99")
    let x_dec_eq_0 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "Lean.Nat.decEq v 0")
    let x_dec_eq_99_getLeaf := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "(.getLeaf x_dec_eq_99)")
    let x_dec_eq_0_getLeaf := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "(.getLeaf x_dec_eq_0)")
    let x_dec_eq_99_getLean1 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "(.getLeaf x_dec_eq_99).getLean1")
    let x_dec_eq_0_getLean1 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "(.getLeaf x_dec_eq_0).getLean1")
    let r_dec_eq_0 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "Lean.Bool.mk bool.tt (Lean.Nat.decEq r 0)")
    let s_dec_eq_0 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "Lean.Bool.mk bool.tt (Lean.Nat.decEq s 0)")
    return Lean.Parser.mkTerm ctx (Lean.Parser.mkApp ctx (Lean.Parser.mkConst ctx `Lean.Bool.mk) [x_dec_eq_99_getLeaf, r_dec_eq_0])
  let r_dec_eq_1 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "Lean.Bool.mk bool.tt (Lean.Nat.decEq r 1)")
  let s_dec_eq_1 := Lean.Parser.runParser ctx (Lean.Parser.parseExpr "Lean.Bool.mk bool.tt (Lean.Nat.decEq s 1)")
  return Lean.Parser.mkTerm ctx (Lean.Parser.mkApp ctx (Lean.Parser.mkConst ctx `Lean.Bool.mk) [x_dec_eq_99_getLeaf, r_dec_eq_1]) ⊎
         Lean.Parser.mkTerm ctx (Lean.Parser.mkApp ctx (Lean.Parser.mkConst ctx `Lean.Bool.mk) [x_dec_eq_0_getLeaf, s_dec_eq_1])

def LTL_G_not_call_reach_error := ∀ (p : Nat → Prop), ∀ (g : Nat → Prop), ∀ (h : Nat → Prop), ∀ (i : Nat),
  (∀ j, g j → h j) → ∀ j, p j → p (S j) → p (S j) ∨ h j

def LTL_G (p : Nat → Prop) : Prop :=
∀ (g : Nat → Prop), ∀ (h : Nat → Prop), ∀ (i : Nat), (∀ j, g j → h j) → ∀ j, p j → p (S j)

def G_not_call_reach_error (p q : Nat → Prop) : Prop :=
∀ (g : Nat → Prop), ∀ (h : Nat → Prop), ∀ (i : Nat), (∀ j, g j → h j) → (∀ j, p j → q j) → p i → q i

def CHECK := ∀ (p : Nat → Prop), ∀ (q : Nat → Prop), (G_not_call_reach_error p q)

def main := do
  let x := init()
  let ⊣p := λ i => Lean.Bool.mk bool.tt (Lean.Nat.decEq i 0)
  let ⊣q := λ i => Lean.Bool.mk bool.tt (Lean.Nat.decEq i 0)
  return CHECK (fun i => ⊣p i) (fun i => ⊣q i)

end Diamond

open Diamond

init

