lean_proof_seed_999:
import Mathlib

open Lean.Elab.Tactics
open Lean.Parser.Tactics
open Lean.Core.Expr
open Lean.Core.Syntax
open Lean.Elab.Attribute
open Lean.Elab.Expression

-- Define types and functions
@[reducible] def bool := Nat
@[reducible] def true := 0
@[reducible] def false := 1

@[reducible] def int := SInt 32

-- Define non-deterministic integer
def nondetInt := do { binding [x ← pure (int.ofNat <| nat.nondet) ] return x }

-- Define main function
def main := do {
  let [x ← nondetInt]
  let [y ← nondetInt]
  let [z ← nondetInt]
  let cond := λ (x : int), λ (y : int), λ (z : int),
    (x <= 10000) ∧ (x >= -10000) ∧ (y <= 10000) ∧ (z <= 10000)
  let body := do {
    let mut x' := x
    while (y > 0) do {
      let mut x'' := x'
      let mut z' := z
      while (y < z) do {
        let mut x''' := x''
        x'' := x''' + 1
        z' := z' - 1
      }
      x' := x''' + y
      y := y - 1
    }
    return 0
  }
  let mainExpr := if cond then body else (pure unit)
  return mainExpr
}

-- Define init expression
def initMain := do {
  let main := main
  return main
}

-- Define LTL property
def end := false
def F := λ (s : Stream bool), ∃ (x : bool), ∀ (i : ℕ), s[i] = x

-- Check property
def prop := CHECK (initMain(), LTL (F end))

-- Elaborate and evaluate the property
runElab <| tactic {
  let prop := elaborator.run <| tactic {
    let prop := `(CHECK (initMain, LTL F end))
    return prop
  }
  let prop := do {
    let prop := tactic.normalize <| tactic.inferType prop
    return tactic.evalExpr prop
  }
  return prop
}

