open Tactic.Mcsara.Utils.Data
open Tactic.Mcsara.Utils.Data.Array

namespace LeanCCode

def CInt := Expr.const `CInt
def CInt_zero := CInt.mk 0
def CInt_succ (e : CInt) : CInt := CInt.mk (nat.succ (e.getNat))

def CCode_main : Expr := do
  let k ← freshX "k"
  let a ← freshArray "a" CInt 1048
  let cond1 := and [a.get 0 = CInt_mk 23, k >= CInt_zero, k < Array.size a]
  let cond2 := a.get k = CInt_mk 42
  let x ← freshX "x"
  let body := do
    let x' ← subtract x k
    let cond3 := x' >= CInt_zero
    let _ ← assume cond3
    return CInt_zero
  let loop := do
    assume cond1
    assume cond2
    let _ ← assume cond3
    let _ ← assume (x >= CInt_zero)
    let e := apply [while, cond1, cond2, body]
    return e
  let main := do
    let _ ← assume (cond1 || cond2) -- since a[0] != a[k], k cannot be 0
    let _ ← assume (k >= 0 && k < 1048)
