import Mathlib

open Lean.Elab.Tactics
open Lean.Parser.Tactics
open Lean.Parser.Term

namespace Main

def init' : IO Unit := do
  let i : Int := 0
  let mut j : Int := 0
  while (i < 100) do
    let mut k : Bool := false
    while (k) do
      set_option linter.uppercase false
      set_option linter.macros true
      let n := expr.applyN Nat.cast <$> (expr.app (expr.const `__VERIFIER_nondet_int) [])
      let b := bool.cast <$> (expr.app (expr.const `__VERIFIER_nondet_int) [])
      let _ := do
        tactic.skip
        tactic.assumptions
      let _ := tactic.assume (b <> bool.tt)
      let _ := tactic.assume (n < 1)
      let _ := tactic.assume (i < 100)
      let _ := tactic.assume (j < 1)
      let _ := tactic.skip
      let _ := tactic.assume (j <> 1)
      let _ := tactic.assume (i <- add_int i 1)
      let _ := tactic.assume (j <- add_int j 1)
      let _ := tactic.assume (k <- or.int (bool.lt_or_eq (add_int j 1) (add_int n 1)) (bool.lt_or_eq i 100))
    let _ := tactic.assume (i <- add_int i 1)
  pure unit

def init : IO Unit := init'

def end : Prop := false

def F : Prop := ∀ (i : Nat), ¬ end

def LTL (p : Prop) : Prop := ∃ (w : ℕ), ∀ (n : ℕ), ∧ (i < n) → p (i)

def main : IO Unit := do
  let _ := init
  let _ := tactic.qed
  let _ := tactic.exact (LTL F)

end Main

