import Mathlib

open Lean.Elab.Tactics
open Lean.Parser.Tactics

namespace Main

def init (main : Unit) : Option Nat := some 0

def overflow (x y : Int) : Bool := ∃ n : Nat, x + y > nat.max

def G' (x y : Int) : Prop := ∀ n : Nat, x + y ≤ nat.max

def G (x y : Int) : Prop := ¬ overflow x y

def LTL_G (p : Prop) : Prop := ∃ n : Nat, ∀ i : Nat, i < n → p

def main : Unit := do
  let x ← tactic.nonDetInt
  let y ← tactic.nonDetInt
  let mut state := (x, y)
  let mut i := 0
  let mut n := 0
  while i < nat.max do
    have h := G state
    let next_state := (state.fst + state.snd, (-2) * state.snd - 1)
    let hNext := G next_state
    have h_while : i < n → h, from h
    have h_next : i < n → hNext, from rfl
    have h_and : h_while i ∧ h_next i, by { exi i, simp [h_and] }
    have h_i : i < nat.max, by { apply lt_max, exact i }
    have h_g : i < nat.max → G next_state, from hNext
    have h_ltl_g : LTL_G (G state) i, by {
      have h_g_i : G state, by { apply h, exact h_g i }
      exact ⟨i, h_g_i⟩
    }
    have h_ltl_g' : LTL_G (G state) (i + 1), by {
      have h_g_i_next : G next_state, by { apply h_g, exact h_g_i }
      exact ⟨i + 1, h_g_i_next⟩
    }
    have h_and' : h_i ∧ h_ltl_g ∧ h_ltl_g', by { exi i, simp [h_and, h_and'] }
    let h := h_and'
    let _ := assumption
    set state := next_state
    set i := i + 1
    set n := n + 1
  have h_ltl_g'' : LTL_G (G state) n, by {
    have h_g_n : G state, by { apply h_g, exact h_g_i }
    exact ⟨n, h_g_n⟩
  }
  have h_ltl_g''' : LTL_G (G state) (n + 1), by {
