def mc91 (n : Int) : Option Int :=
begin
  if hNat.toNat n > 100 then some (n - 10)
  else do
    let rec mc91' n' := do
      let next_n := mc91' (n' + 11)
      pure next_n
    mc91' (n + 11)
end

def init : Unit := do
  let x := ∥⁡option.get⁡ <| some <| nat.nondet
  mc91 x

def valid_free : Prop := ∀ (n : Int), mc91 n = some <| some <| mv_nat n

def valid_deref : Prop := ∀ (n : Int), mc91 n <|> Option.none = mc91 (mc91 (some <| some <| mv_nat (n + 11)))

def valid_memtrack : Prop := ∀ (n : Int), mc91 n = some <| some <| mv_nat n ∨ mc91 n = Option.none

