  let h'''''''' : ∀ s, ∀ i, i < 1000 → s i = 0 ∨ s i = ∥⁡option.get⁡ <| Option.none, by { intros s i; apply h''''' i hi.symm }
  let h''''''''': ∀ s, ∀ i, i < 1000 → s i = ∥⁡option.get⁡ <| Option.none → s i = 0, by { intros s i hs hn; apply h'''''' i hs hn }
  let h'''''''''' : ∀ s, ∀ i, i < 1000 → s i = ∥⁡option.get⁡ <| Option.none → s = Array.fill Array.emptyInt 1000 Int.zero, by { intros s i hs hn; apply h'''''' i hs hn; apply h'''' h }
  let h''''''''''' : ∀ s, s = Array.fill Array.emptyInt 1000 Int.zero → ∀ i, i < 1000 → s i = 0, by { intros s hs i; apply h'''''''' hs i }
