  let h''''''''''''' : ∀ s, s = Array.fill Array.emptyInt 1000 Int.zero → ∀ i, i < 1000 → s i = ∥⁡option.get⁡ <| mc91 i, by { intros s hs i; apply h'''''''' hs i; apply valid_free }
  let h'''''''''''''' : ∀ s, s = Array.fill Array.emptyInt 1000 Int.zero → ∀ i, i < 1000 → s i = Option.none, by { intros s hs i; apply h'''''''' hs i; apply valid_memtrack }
