  let h'''''''''''''''' : ∀ s, s = Array.fill Array.emptyInt 1000 Int.zero → ∀ i, i < 1000 → s i = ∥⁡option.get⁡ <| Option.none → s = Array.fill Array.emptyInt 1000 Int.zero, by { intros s hs i hn; apply h''''''''''' hs i hn }
  let h''''''''''''''''': ∀ s, s = Array.fill Array.emptyInt 1000 Int.zero → ∀ i, i < 1000 → s i = ∥⁡option.get⁡ <| mc91 i → s = Array.fill Array.emptyInt 1000 Int.zero, by { intros s hs i hi; apply h'''''''''''' hs i hi }
  let h'''''''''''''''''' : ∀ s, s = Array.fill Array.emptyInt 1000 Int.zero → ∀ i, i < 1000 → s i = ∥⁡option.get⁡ <| Option.none → s i = ∥⁡option.get⁡ <| mc91 i, by { intros s hs i hn hi; apply h''''''''''''' hs i hn hi }
