namespace Main

@[inline] def init : IO Unit := do
  let p ← malloc (sizeOf <| box ℤ)
  let mut i := 0
  while (∥ i <- nat.cast <| sizeOf ℤ <|>.map (λ n => box (n.toNat.toInt)) <| io.repeatM (fun _ => do
