import Mathlib

open Lean.Elab.Tactics
open Lean.Elab.Expression
open Lean.Elab.Term
open Lean.Syntax
open Lean.SyntaxShell
open Lean.Parser.Tactic

-- C Code to Lean 4 Function Definition
def SelectionSort (a : Array Int) : Unit :=
do {
  let size := a.length
  let i := 0
  repeat (do {
    let j := i + 1
    let min := i
    repeat (do {
      let current_min := get_ref a i
      let next_min := get_ref a j
      set_ref a i (get_ref a j)
      set_ref a j current_min
      let temp := current_min
      set_ref a i temp
      set_ref a j next_min
      set_ref i (succ i)
      unless (i < size) (return ())
    })
  })
}

-- Main Function
def main : Unit := do {
  let a <- Array.mk <$> (repeatedly (fun () => some <| randomInt 10)) (nat.ofInt 10)
  SelectionSort a
  let valid_free := ∀ i, 0 ≤ i < a.length ↔ is_null (get_ref a i)
  let valid_deref := ∀ i, 0 ≤ i < a.length → is_nonnull (get_ref a i)
  let valid_memtrack := ∀ i, 0 ≤ i < a.length → is_nonnull (get_ref a i) ∧ get_ref a i ≠ get_ref a i
  let init := fun () => { a := a }
  let _ := checkInit (init fun () => main) valid_free valid_deref valid_memtrack
  pure 0
}

-- Specification
def init (f : Fun (Option Unit) Unit) : Prop :=
∀ σ, ∃ s, ∀ γ, ∃ σ', σ = σ.apply γ ∧ f σ = s

def LTL (p : Prop) : Prop := ∃ σ, ∀ i, p ∧ σ(i) = Some (i + 1)

def G (p : Prop) : Prop := ∀ i, p i ∨ p (succ i)

def valid_free : Prop := ∀ i, 0 ≤ i < a.length ↔ is_null (get_ref a i)
def valid_deref : Prop := ∀ i, 0 ≤ i < a.length → is_nonnull (get_ref a i)
def valid_memtrack : Prop := ∀ i, 0 ≤ i < a.length → is_nonnull (get_ref a i) ∧ get_ref a i ≠ get_ref a (succ i)

-- Specification Checking
def checkInit (f : Fun (Option Unit) Unit) (valid_free : Prop) (valid_deref : Prop) (valid_memtrack : Prop) : Prop :=
∀ σ, (valid_free ∧ valid_deref ∧ valid_memtrack) σ →
∃ s, ∀ γ, ∃ σ', σ = σ.apply γ ∧ f σ = s

-- Main Execution
initMain <| fun () => main.toExpr.getConstFn <| [| main |]

-- Specification Checking
let _ := checkInit (initMain fun () => main) valid_free valid_deref valid_memtrack
-- LTL Checking
let _ := checkLTL (initMain fun () => main) (LTL valid_free) (LTL valid_deref) (LTL valid_memtrack)
-- G Checking
let _ := checkG (initMain fun () => main) valid_free valid_deref valid_memtrack

-- Exit
pure Unit

