lean_proof_seed_42:
import Mathlib

open Lean.Elab.Tactic.Basic
open Lean.Elab.Tactics.Term

def id (x : ℕ) : ℕ :=
if h : x = 0 then 0
else id.rec hx (x - 1) + 1

def id_le_two (x : ℕ) : ℕ → Prop :=
x ≤ 2

def main : ℕ :=
unsafeCoercion <| __VERIFIER_nondet_uint _

def main_precondition : Prop :=
∀ (x : ℕ), id_le_two x → true

def main_postcondition : Prop :=
∀ (x : ℕ), id x ≠ 3

def init : Unit := do
  let input ← fresh "input"
  let result ← id input
  let _ ← assume (id_le_two input)
  return ()

def init_main : Prop :=
init.run main_precondition && LTL.always (LTL.neg (id_le_three result))

def id_le_three (x : ℕ) : Prop :=
x ≤ 3

def main_end : Prop := true

def main_loop : Prop :=
init_main && main_end

def main_spec : Prop :=
main_loop

set_option pp.all false in
#check main_spec
